gt = first_10 + [{'question': q, 'correct_answer': a} for q, a in next_20_topics]

gt_str = 'GROUND_TRUTH = [\n'
for item in gt:
    gt_str += '    {\n'
    gt_str += f'        "question": "{item["question"]}",\n'
    gt_str += f'        "correct_answer": "{item["correct_answer"]}"\n'
    gt_str += '    },\n'
gt_str += ']\n'

for fpath in ['app.py', 'data/knowledge.py']:
    content = pathlib.Path(fpath).read_text(encoding='utf-8')
    pattern = re.compile(r'GROUND_TRUTH\s*=\s*\[.*?\]\s*', re.DOTALL)
    new_content = pattern.sub(gt_str.strip() + '\n\n', content)
    pathlib.Path(fpath).write_text(new_content, encoding='utf-8')
print('Done replacing GROUND_TRUTH in both files')
